val recipeFiles = searchFilesByFilename(filename = "recipe-collection.docx")
val groceryListFiles = searchFilesByFilename(filename = "grocery")

val result = recipeFiles.flatMap { recipes =>
  groceryListFiles.map { groceries =>
    if (recipes.isEmpty) {
      "Error: recipe-collection.docx not found."
    } else if (groceries.isEmpty) {
      "Error: grocery list file not found."
    } else {
      val recipeFileId = recipes.head.id
      val groceryListFileId = groceries.head.id
      val recipeContent = getFileById(recipeFileId).map(_.content)
      val ingredients = recipeContent.map(c => prompt(s"Extract the list of ingredients for the Chocolate Chip Cookies recipe from this text: $c"))
      ingredients.map(i => appendToFile(groceryListFileId, "\n" + i))
      s"Ingredients from Chocolate Chip Cookies recipe added to grocery list."
    }
  }
}

displaySecurely(result)

